// Auto-generated by daily-inbox-to-tasks scheduled task — 2026-06-22
// Run: node --env-file=.env.local scripts/inbox-tasks-2026-06-22.mjs
import { createClient } from "@supabase/supabase-js";

const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

if (!url || !key) {
  console.error("Missing NEXT_PUBLIC_SUPABASE_URL or NEXT_PUBLIC_SUPABASE_ANON_KEY");
  process.exit(1);
}

const supabase = createClient(url, key);

const NEW_TASKS = [
  // ── URGENT ──
  {
    text: "Confirm SWFFM student-dorm waitlist application — click the confirmation link in the email from noreply@swffm.de (received 22 Jun) within 7 days or your Bewerbung Nr. 549080 will be dropped. Deadline: 29 June 2026. wohnen@swffm.de",
    due_date: "2026-06-29",
    priority: "urgent",
  },
  // ── IMPORTANT ──
  {
    text: "File Indian Income Tax Return (ITR) for FY 2025-2026 — Form 16 received from TechMahindra (PACEHR@techmahindra.com, 21 Jun). Use it to file on incometax.gov.in before 31 July 2026.",
    due_date: "2026-07-31",
    priority: "important",
  },
];

const rows = NEW_TASKS.map((t) => ({
  text: t.text,
  notes: null,
  due_date: t.due_date || null,
  category: null,
  step_order: null,
  status: "active",
  priority: t.priority,
  completed_at: null,
}));

const { data, error } = await supabase.from("tasks").insert(rows).select("id, priority");

if (error) {
  console.error("Insert failed:", error.message);
  process.exit(1);
}

const byPriority = data.reduce((acc, r) => {
  acc[r.priority] = (acc[r.priority] || 0) + 1;
  return acc;
}, {});
console.log(`Done. Inserted ${data.length} tasks:`, byPriority);
